def list_ollama_embedding_models() -> List[str]:
    """List available embedding models from local Ollama."""
    global _ollama_models_cache, _ollama_models_cache_time
    import requests

    # 60 seconds TTL cache
    current_time = time.time()
    if current_time - _ollama_models_cache_time < 60.0 and _ollama_models_cache:
        return _ollama_models_cache

    try:
        response = requests.get("http://localhost:11434/api/tags", timeout=5)
        if response.status_code == 200:
            models = response.json().get("models", [])
            # Filter models that can be used for embeddings (typically have "embed" in name)
            _ollama_models_cache = [m["name"] for m in models if "embed" in m["name"].lower() or "nomic" in m["name"].lower()]
            _ollama_models_cache_time = current_time
            return _ollama_models_cache
    except Exception:
        pass

    # Only fallback to default if cache is empty and request fails
    if not _ollama_models_cache:
        return ["nomic-embed-text"]  # Default
    return _ollama_models_cache


class DocumentProcessor:
    def __init__(self, chunk_size: int = 1000, chunk_overlap: int = 200):
        self.text_splitter = RecursiveCharacterTextSplitter(
            chunk_size=chunk_size,
            chunk_overlap=chunk_overlap,
            length_function=len,
        )

    def process_file(self, file_path: str) -> List[Document]:
        """Loads a PDF and splits it into chunks."""
        if not os.path.exists(file_path):
            raise FileNotFoundError(f"File not found: {file_path}")

        loader = PyPDFLoader(file_path)
        documents = loader.load()
        chunks = self.text_splitter.split_documents(documents)
        return chunks

